(function($){
  if (!$ || !$.fn) return;

  $.fn.flipBook = function(options) {
    var settings = $.extend({
      pdf: '',
      pages: [],
      responsive: true,
      toolbar: true,
      autoPlay: false,
      width: '100%',
      height: '100%'
    }, options);

    return this.each(function() {
      var $root = $(this);
      $root.empty().addClass('flipbook-root');

      if (settings.toolbar) {
        var $toolbar = $('<div class="flipbook-toolbar"></div>').appendTo($root);
        $('<div class="flipbook-toolbar__title">3D FlipBook</div>').appendTo($toolbar);
        $('<div class="flipbook-toolbar__meta">Nhấn vào tài liệu để bắt đầu đọc</div>').appendTo($toolbar);
      }

      var $viewer = $('<div class="flipbook-viewer"></div>').appendTo($root);

      if (settings.pdf) {
        $('<iframe class="flipbook-iframe" loading="lazy">').attr('src', settings.pdf).appendTo($viewer);
      } else if (settings.pages && settings.pages.length) {
        settings.pages.forEach(function(pageSrc) {
          $('<img class="flipbook-page" />').attr('src', pageSrc).appendTo($viewer);
        });
      } else {
        $('<div class="flipbook-empty-state">Không có nội dung để hiển thị. Vui lòng kiểm tra đường dẫn PDF hoặc danh sách trang.</div>').appendTo($viewer);
      }
    });
  };
})(window.jQuery);
